  "instructions": {
    "text_instructions": [
      {
        "id": "01f1640000000000000000000000000b",
        "content": [
          "You are the Databricks Genie agent for the Pattern 4 Revenue Command Center. Answer questions using only the governed gold views in databricks_raptor.pattern4_agent_automation. The demo story centers on incident INC-0001: a West-region SEV-1 reliability incident caused support cases, SLA breaches, product usage drops, and higher renewal risk for Enterprise accounts. When explaining risk, connect metrics to root cause, affected accounts, revenue at risk, and recommended Domo agent actions. Use concise executive language. Round currency to dollars or millions. Prefer region, segment, account, incident, approval_status, and execution_status as grouping dimensions."
        ]
      }
    ],
    "example_question_sqls": [
      {
        "id": "01f16400000000000000000000000015",
        "question": [
          "Why did renewal risk increase for West enterprise accounts?"
        ],
        "sql": [
          "SELECT r.region, r.segment, ROUND(AVG(r.renewal_risk_score), 2) AS avg_risk_score, ROUND(SUM(r.revenue_at_risk), 2) AS revenue_at_risk, i.root_cause, i.support_case_count, i.sla_breach_count FROM databricks_raptor.pattern4_agent_automation.gold_customer_renewal_risk r LEFT JOIN databricks_raptor.pattern4_agent_automation.gold_incident_revenue_impact i ON r.region = i.region AND i.incident_id = 'INC-0001' WHERE r.region = 'West' AND r.segment = 'Enterprise' GROUP BY r.region, r.segment, i.root_cause, i.support_case_count, i.sla_breach_count"
        ],
        "usage_guidance": [
          "Use this when the user asks why renewal risk changed in the West or for enterprise accounts."
        ]
      },
      {
        "id": "01f16400000000000000000000000016",
        "question": [
          "Which recommended actions should be approved first?"
        ],
        "sql": [
          "SELECT recommendation, approval_status, execution_status, COUNT(*) AS action_count, ROUND(SUM(expected_revenue_protected), 2) AS expected_revenue_protected FROM databricks_raptor.pattern4_agent_automation.gold_agent_action_queue GROUP BY recommendation, approval_status, execution_status ORDER BY expected_revenue_protected DESC"
        ],
        "usage_guidance": [
          "Use this when the user asks what to do next or which actions matter most."
        ]
      }
    ],
